<span class="line"><span style="color:#EBA0AC;font-style:italic;">    scores</span><span style="color:#9399B2;">[</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#A6E3A1;font-style:italic;">overall</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">]</span><span style="color:#94E2D5;"> =</span><span style="color:#9399B2;"> (</span></span>
