<span class="line"><span style="color:#CDD6F4;">        code </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;"> call_llm</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;font-style:italic;">f</span><span style="color:#A6E3A1;">&quot;&quot;&quot;</span></span>
